#include <stdio.h>
#define MOD 1000000007LL

long long modPow(long long base, long long exp) {
    long long res = 1;
    while (exp > 0) {
        if (exp & 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long n;
        scanf("%lld", &n);
        long long pow2 = modPow(2, n - 1);
        long long ans = (272LL * pow2) % MOD;
        ans = (ans + (n - 1) % MOD) % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

